    # base case
    if n == 1:
        return True
    # for loop
    for i in range(1, n):
        if arr[i - 1] < arr[i]:
            break
    # if condition
    if i == n:
        return True
    # initialize j
    j = i + 1
    # while loop
    while arr[j] < arr[j - 1]:
        # nested if condition
        if i > 1 and arr[j] < arr[i - 2]:
            return False
        j += 1
    # if condition
    if j == n:
        return True
    # initialize k
    k = j
    if arr[k] < arr[i - 1]:
        return False
    # while loop
