def KnapSack(val, wt, n, W):
    mat = [[0 for i in range(W+1)] for i in range(2)]
    i = 0
    while i < n:
        j = 0
        if i % 2 != 0:
            while j <= W:
                if wt[i] <= j and j - wt[i] < W:
                    mat[1][j] = max(val[i] + mat[0][j - wt[i]], mat[0][j])
                else:
                    mat[1][j] = mat[0][j]
                j += 1
        else:
            while j <= W:
                if wt[i] <= j and j - wt[i] < W:
                    mat[0][j] = max(val[i] + mat[1][j - wt[i]], mat[1][j])
                else:
                    mat[0][j] = mat[1][j]
                j += 1
        i += 1
    return (n % 2 != 0) * mat[0][W] + (n % 2 == 0) * mat[1][W]

